def classify_animal(legs, has_fur):
    if legs == 8:
        return "Spider"
    elif legs == 4 and has_fur:
        return "Mammal (like a dog!)"
    elif legs == 2 and not has_fur:
        return "Bird"
    else:
        return "Not sure — need more clues!"

print(classify_animal(8, False))
print(classify_animal(4, True))
print(classify_animal(2, False))
